var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"일단은 제가 네퀴티아에게 남아 있는 인간성이라고 가정해 볼게요.","JPN":"とりあえず私がネキティアに残っている人間性だと仮定しましょう。","ENG":"Let's say I'm the last humanity remaining within Nequitia, for now.","TWN":"總之，先假設我是莉奎蒂亞殘存的人性。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"여지 없는 사실이다. 나는 너에게 거짓을 이르지 않았으니.","JPN":"疑いようのない事実だ。我はそなたに嘘などついておらぬ。","ENG":"It is the irrefutable truth. I have not told you a lie.","TWN":"這是不爭的事實，我沒有對你說謊。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"말이 그렇다는 거예요.","JPN":"それはわかっています。","ENG":"I'm just saying.","TWN":"我說說而已。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"만약 그렇다면, 어째서 한가롭게 열차 여행이나 하고 있는 거죠?","JPN":"だとしたら、どうして私は呑気に列車の旅なんてやっているんですか？","ENG":"If so, why am I on a leisurely train ride?","TWN":"假設真是如此，那我為何還悠哉地火車旅行呢？"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네퀴티아….","JPN":"ネキティア……","ENG":"Nequitia...","TWN":"莉奎蒂亞…"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"다시 말해, 너에게 이 열차의 모든 것은 어디론가 멀리 떠나보내야 할 경험들이다.","JPN":"つまり、そなたにとってこの列車で起こるすべては、どこか遠くに追いやるべき経験なのだ。","ENG":"In other words, for you, this train embodies the experiences you are to send somewhere distant.","TWN":"我再說一次，這台列車裡的一切對你而言，就是要送到遠方某處的經歷。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"우리 그냥 구분해서 말하면 어때요?","JPN":"そうやって毎回二度言うのはやめませんか？","ENG":"How about we just separate the two?","TWN":"可以不要一直把我們混為一談嗎？"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"고지식하게 매번 지적해 주지 않아도 잘 알고 있거든요. 네퀴티아가 저라는 건.","JPN":"いちいち言われなくてもわかっています、私がネキティアなのは。","ENG":"I'm well aware that I'm Nequitia. You don't have to point it out every time.","TWN":"不需要你一直提醒我，我也知道我就是莉奎蒂亞。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"좋다. 그러길 원한다면.","JPN":"よかろう。そう望むなら。","ENG":"Very well. If that is your wish.","TWN":"好吧，就照你的意思。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"하지만 네퀴티아 자신도 어디로 보내야 할지, 어떻게 보내야 할지는 모르고 있는 모양이더군.","JPN":"だが、ネキティア自身もどこに追いやるべきか、どう追いやるべきかをわかっていないようだ。","ENG":"However, it seemed like Nequitia herself did not know where to send the train, or how to send one.","TWN":"不過莉奎蒂亞自己似乎也不知道要送去哪，又該如何送。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래서 같은 철로를 계속 달리는 열차란 말이죠.","JPN":"だから列車が同じ線路を走り続けている、ということですね。","ENG":"And that's why this train runs endlessly on the same track.","TWN":"所以才會一直重複相同的路線對吧。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하고 다니는 짓이랑 안 맞게 마음만은 소녀네요. 나 원, 참.","JPN":"やっていることとは裏腹に、心は少女のようですね。呆れるわ、まったく。","ENG":"She's a little girl on the inside while doing the opposite on the outside. How ironic.","TWN":"和她平時的作風一點都不像，內心根本還是少女吧，真是的。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜 갑자기 멈춰요?","JPN":"急に止まって、どうしたんですか？","ENG":"Why did you stop?","TWN":"怎麼突然不說話？"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이 문을 열고 들어가면 다음 객차다, 레아 슈나이더.","JPN":"このドアを開ければ次の客車だ、レア・シュナイダー。","ENG":"Beyond this gate is the next passenger vehicle, Leah Schneider.","TWN":"打開這道門後就是下一節車廂，蕾亞·修奈德。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"객차마다 무엇이 있는지는 나 역시 명확히 알지 못한다.","JPN":"客車ごとに何があるかは、我とて正確にはわからぬ。","ENG":"I do not know of what lies in each passenger vehicle.","TWN":"我也無法明確掌握每節車廂裡會出現什麼。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그러니 무엇을 보더라도 삼켜지지 마라.","JPN":"ゆえに、何を目にしたとしても飲まれるな。","ENG":"Therefore, do not get consumed by whatever it is that you witness.","TWN":"所以不管你等下看到什麼，都不要被吞吃掉。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};